using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>().ToContainer("Products");

        // EF Core 9 renamed the default discriminator property from "Discriminator" to "$type".
        // Existing 500K documents use "Discriminator", and direct SQL queries reference c.Discriminator.
        modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

        // EF Core 9 no longer embeds the discriminator in the JSON id property.
        // Existing documents have ids in "Product|123" format; without this flag,
        // FindAsync would look for "123" and miss every existing document.
        modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);

        // REMOVED: .HasIndex(p => p.Sku)
        // EF Core 9 Cosmos provider throws on HasIndex at startup.
        // Cosmos DB indexing is managed via the container's indexing policy (Azure Portal / Bicep / Terraform).
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

